using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this app.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearch),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetNotes),
};

// --- Create the research agent ---
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI agent that researches topics by searching the web and taking notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
        },
    });

// --- Run the agent loop ---
Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):");
Console.Write("> ");

var session = await agent.CreateSessionAsync();

while (Console.ReadLine() is { } input && !input.Equals("quit", StringComparison.OrdinalIgnoreCase))
{
    if (string.IsNullOrWhiteSpace(input))
    {
        Console.Write("> ");
        continue;
    }

    notes.Clear();

    var prompt = $"""
        Research the following topic by searching the web multiple times to gather information.
        Save important findings as notes. After gathering enough information, provide a
        comprehensive summary of your research.

        Topic: {input}

        Instructions:
        1. Search the web for relevant information (perform 2-3 searches with different queries).
        2. Save key findings as notes using the note-taking tool.
        3. Review your notes and provide a final summary.
        """;

    Console.WriteLine("\nResearching...\n");

    var response = await agent.RunAsync(prompt, session, new ChatClientAgentRunOptions
    {
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
        },
    });

    Console.WriteLine(response.Text);
    Console.WriteLine();
    Console.Write("> ");
}

Console.WriteLine("Goodbye!");
return;

// --- Tool implementations ---

List<string> notes = [];

[Description("Search the web for information on a query. Returns relevant search results.")]
static string WebSearch([Description("The search query")] string query)
{
    // Simulated web search - in production, integrate with Bing Search API or similar
    Console.WriteLine($"  [Tool] Searching web: \"{query}\"");

    var results = new[]
    {
        new { Title = $"Result 1 for '{query}'", Snippet = $"Comprehensive overview of {query} covering key aspects and recent developments." },
        new { Title = $"Result 2 for '{query}'", Snippet = $"Expert analysis on {query} highlighting important trends and implications." },
        new { Title = $"Result 3 for '{query}'", Snippet = $"Latest research findings about {query} from leading institutions." },
    };

    return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
}

[Description("Save a research note for later reference.")]
string SaveNote(
    [Description("Title of the note")] string title,
    [Description("Content of the note")] string content)
{
    Console.WriteLine($"  [Tool] Saving note: \"{title}\"");
    notes.Add($"## {title}\n{content}");
    return $"Note saved: '{title}' ({notes.Count} total notes)";
}

[Description("Retrieve all saved research notes.")]
string GetNotes()
{
    Console.WriteLine("  [Tool] Retrieving notes...");
    if (notes.Count == 0)
        return "No notes saved yet.";

    return string.Join("\n\n", notes);
}

